import { useState } from "react";

function App() {
    const [resumeText, setResumeText] = useState("");
    const [jobDescription, setJobDescription] = useState("");
    const [analysis, setAnalysis] = useState(null);
    const [file, setFile] = useState(null);
    const [fileName, setFileName] = useState("");
    const [loading, setLoading] = useState(false);
    const [uploadMessage, setUploadMessage] = useState("");

    const analyzeResume = async () => {
        if (resumeText.trim() === "") {
            setAnalysis({
                score: 0,
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Please paste your resume content first."]
            });
            return;
        }

        setLoading(true);
        setUploadMessage("");

        try {
            const response = await fetch("http://localhost:5000/analyze", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json"
                },
                body: JSON.stringify({ resumeText, jobDescription })
            });

            const data = await response.json();
            setAnalysis(data);
        } catch (error) {
            setAnalysis({
                score: 0,
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Error connecting to backend."]
            });
        } finally {
            setLoading(false);
        }
    };

    const uploadResume = async () => {
        if (!file) {
            setUploadMessage("Please choose a PDF file first.");
            return;
        }

        setLoading(true);
        setUploadMessage("");
        setAnalysis(null);

        const formData = new FormData();
        formData.append("resume", file);

        try {
            const response = await fetch("http://localhost:5000/upload", {
                method: "POST",
                body: formData
            });

            const data = await response.json();

            if (data.extractedText) {
                setResumeText(data.extractedText);
            }

            setUploadMessage(data.message || "Resume extracted successfully.");
        } catch (error) {
            setUploadMessage("Error uploading PDF.");
        } finally {
            setLoading(false);
        }
    };

    const tagStyle = {
        display: "inline-block",
        padding: "8px 12px",
        borderRadius: "20px",
        margin: "6px",
        fontSize: "14px",
        fontWeight: "bold"
    };

    const getScoreColor = (score) => {
        if (score >= 80) return "#28a745";
        if (score >= 60) return "#ffc107";
        return "#dc3545";
    };

    const buttonStyle = {
        border: "none",
        padding: "12px 20px",
        borderRadius: "8px",
        cursor: "pointer",
        fontSize: "16px",
        color: "white"
    };

    return (
        <div
            style={{
                minHeight: "100vh",
                backgroundColor: "#f4f7fb",
                display: "flex",
                justifyContent: "center",
                alignItems: "center",
                fontFamily: "Arial, sans-serif",
                padding: "20px"
            }}
        >
            <div
                style={{
                    backgroundColor: "white",
                    padding: "30px",
                    borderRadius: "12px",
                    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
                    width: "800px"
                }}
            >
                <h1 style={{ textAlign: "center" }}>AI Resume Analyzer 🚀</h1>
                <p style={{ textAlign: "center" }}>
                    Upload a PDF to fill your resume, then paste a job description and click Analyze Match.
                </p>

                <h3>Upload Resume PDF</h3>
                <input
                    type="file"
                    accept=".pdf"
                    onChange={(e) => {
                        setFile(e.target.files[0]);
                        setFileName(e.target.files[0]?.name || "");
                    }}
                />

                {fileName && (
                    <p style={{ fontSize: "14px", marginTop: "8px", color: "#555" }}>
                        Selected: {fileName}
                    </p>
                )}

                <div style={{ textAlign: "center", marginTop: "12px", marginBottom: "20px" }}>
                    <button
                        onClick={uploadResume}
                        style={{
                            ...buttonStyle,
                            backgroundColor: "#28a745"
                        }}
                    >
                        {loading ? "Uploading..." : "Upload & Extract Resume"}
                    </button>
                </div>

                {uploadMessage && (
                    <p
                        style={{
                            backgroundColor: "#e8f5e9",
                            color: "#1b5e20",
                            padding: "10px",
                            borderRadius: "8px",
                            marginBottom: "20px"
                        }}
                    >
                        {uploadMessage}
                    </p>
                )}

                <h3>Resume</h3>
                <textarea
                    placeholder="Paste resume..."
                    value={resumeText}
                    onChange={(e) => setResumeText(e.target.value)}
                    style={{
                        width: "100%",
                        height: "160px",
                        padding: "12px",
                        borderRadius: "8px",
                        border: "1px solid #ccc",
                        resize: "none",
                        fontSize: "14px"
                    }}
                />

                <h3 style={{ marginTop: "20px" }}>Job Description</h3>
                <textarea
                    placeholder="Paste job description..."
                    value={jobDescription}
                    onChange={(e) => setJobDescription(e.target.value)}
                    style={{
                        width: "100%",
                        height: "140px",
                        padding: "12px",
                        borderRadius: "8px",
                        border: "1px solid #ccc",
                        resize: "none",
                        fontSize: "14px"
                    }}
                />

                <div style={{ textAlign: "center", marginTop: "12px" }}>
                    <button
                        onClick={analyzeResume}
                        style={{
                            ...buttonStyle,
                            backgroundColor: "#007bff"
                        }}
                    >
                        {loading ? "Analyzing..." : "Analyze Match"}
                    </button>
                </div>

                {analysis && (
                    <div style={{ marginTop: "24px" }}>
                        <div
                            style={{
                                backgroundColor: "#eef4ff",
                                padding: "20px",
                                borderRadius: "8px",
                                marginBottom: "15px"
                            }}
                        >
                            <h3 style={{ marginBottom: "12px" }}>Score: {analysis.score}/100</h3>

                            <div
                                style={{
                                    height: "16px",
                                    backgroundColor: "#ddd",
                                    borderRadius: "999px",
                                    overflow: "hidden"
                                }}
                            >
                                <div
                                    style={{
                                        width: `${analysis.score}%`,
                                        height: "100%",
                                        backgroundColor: getScoreColor(analysis.score),
                                        transition: "width 0.4s ease"
                                    }}
                                />
                            </div>
                        </div>

                        <div
                            style={{
                                backgroundColor: "#f8f9fa",
                                padding: "15px",
                                borderRadius: "8px",
                                marginBottom: "15px"
                            }}
                        >
                            <h3>Matched Skills</h3>
                            <div style={{ display: "flex", flexWrap: "wrap" }}>
                                {analysis.matchedSkills && analysis.matchedSkills.length > 0 ? (
                                    analysis.matchedSkills.map((skill, index) => (
                                        <span
                                            key={index}
                                            style={{
                                                ...tagStyle,
                                                backgroundColor: "#d4edda",
                                                color: "#155724"
                                            }}
                                        >
                      {skill}
                    </span>
                                    ))
                                ) : (
                                    <p>No matched skills found</p>
                                )}
                            </div>
                        </div>

                        <div
                            style={{
                                backgroundColor: "#fff8e1",
                                padding: "15px",
                                borderRadius: "8px",
                                marginBottom: "15px"
                            }}
                        >
                            <h3>Missing Skills</h3>
                            <div style={{ display: "flex", flexWrap: "wrap" }}>
                                {analysis.missingSkills && analysis.missingSkills.length > 0 ? (
                                    analysis.missingSkills.map((skill, index) => (
                                        <span
                                            key={index}
                                            style={{
                                                ...tagStyle,
                                                backgroundColor: "#f8d7da",
                                                color: "#721c24"
                                            }}
                                        >
                      {skill}
                    </span>
                                    ))
                                ) : (
                                    <p>No missing skills</p>
                                )}
                            </div>
                        </div>

                        <div
                            style={{
                                backgroundColor: "#fcebea",
                                padding: "15px",
                                borderRadius: "8px"
                            }}
                        >
                            <h3>Suggestions</h3>
                            {analysis.suggestions && analysis.suggestions.length > 0 ? (
                                <ul>
                                    {analysis.suggestions.map((item, index) => (
                                        <li key={index} style={{ marginBottom: "8px" }}>
                                            {item}
                                        </li>
                                    ))}
                                </ul>
                            ) : (
                                <p>No suggestions</p>
                            )}
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

export default App;
